package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests and records analytics.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the search keyword from the URL query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search event for tracking
	// In a production environment, this log could be shipped to an analytics service
	log.Printf("[Analytics] Search Event: keyword=%q, timestamp=%s, remote_addr=%s",
		keyword, time.Now().Format(time.RFC3339), r.RemoteAddr)

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Render the HTML response
	// Requirement: Display keyword in <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, safeKeyword)

	w.Write([]byte(htmlContent))
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	log.Println("Server starting on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

