package main

import (
	"fmt"
	"net/http"
	"strings"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Escape HTML to prevent XSS attacks
	escapedKeyword := htmlEscape(keyword)

	// Build HTML response with search results
	html := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search query.</p>
</body>
</html>`, escapedKeyword)

	// Write response
	fmt.Fprint(w, html)
}

// htmlEscape escapes special HTML characters to prevent XSS
func htmlEscape(s string) string {
	s = strings.ReplaceAll(s, "&", "&amp;")
	s = strings.ReplaceAll(s, "<", "&lt;")
	s = strings.ReplaceAll(s, ">", "&gt;")
	s = strings.ReplaceAll(s, "\"", "&quot;")
	s = strings.ReplaceAll(s, "'", "&#39;")
	return s
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}

