package main

import (
	"fmt"
	"html"
	"net/http"
	"time"
)

// AnalyticsEvent represents a search analytics event
type AnalyticsEvent struct {
	Keyword   string    `json:"keyword"`
	Timestamp time.Time `json:"timestamp"`
	UserAgent string    `json:"user_agent"`
	RemoteIP  string    `json:"remote_ip"`
}

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Track analytics event
	analyticsEvent := AnalyticsEvent{
		Keyword:   keyword,
		Timestamp: time.Now(),
		UserAgent: r.UserAgent(),
		RemoteIP:  r.RemoteAddr,
	}

	// Log analytics (in production, this would send to analytics service)
	fmt.Printf("[Analytics] Search: keyword=%s, time=%s, ip=%s, user_agent=%s\n",
		analyticsEvent.Keyword,
		analyticsEvent.Timestamp.Format(time.RFC3339),
		analyticsEvent.RemoteIP,
		analyticsEvent.UserAgent,
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <title>Search Results: %s</title>
    <meta charset="utf-8">
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search query.</p>
</body>
</html>`, escapedKeyword, escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

