            <p>Search performed at: %s</p>
        </div>
    </div>
</body>
</html>`, escapedKeyword, escapedKeyword, escapedKeyword, time.Now().Format(time.RFC3339))

	// Write the response
	fmt.Fprint(w, htmlContent)
}

// logAnalytics logs search analytics data
func logAnalytics(r *http.Request, keyword string) {
	analytics := AnalyticsData{
		Keyword:   keyword,
		Timestamp: time.Now(),
		IPAddress: r.RemoteAddr,
		UserAgent: r.UserAgent(),
	}

	log.Printf("Search Analytics - Keyword: %s, IP: %s, Time: %s, User-Agent: %s",
		analytics.Keyword,
		analytics.IPAddress,
		analytics.Timestamp.Format(time.RFC3339),
		analytics.UserAgent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

