package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log the search request
	logAnalytics(r, keyword)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search query.</p>
</body>
</html>`, escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

// logAnalytics logs search analytics information
func logAnalytics(r *http.Request, keyword string) {
	log.Printf("[%s] Search Request - Keyword: %s, IP: %s, User-Agent: %s",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
		r.UserAgent())
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatal(err)
	}
}

