package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// recordAnalytics simulates sending search data to an analytics service.
// In a production environment, this would likely send data to a dedicated analytics backend.
func recordAnalytics(keyword string) {
	timestamp := time.Now().Format(time.RFC3339)
	log.Printf("[Analytics] Event: Search | Timestamp: %s | Keyword: %s", timestamp, keyword)
}

// HandleProductSearch handles the product search requests.
// It extracts the keyword, records analytics, and returns an HTML response.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Ensure only GET requests are processed
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics support: Record the search event
	recordAnalytics(keyword)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Construct and write the HTML response
	// Requirement: Display <h2>Search Results: [keyword]</h2>
	htmlTemplate := `<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`

	fmt.Fprintf(w, htmlTemplate, safeKeyword)
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	addr := ":8080"
	log.Printf("Starting server on %s", addr)
	if err := http.ListenAndServe(addr, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

