// HandleProductSearch handles the product search request with analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log the search event with timestamp
	// In a production environment, this could push to a dedicated analytics service
	log.Printf("[Analytics] Search Event | Time: %s | Keyword: %s | IP: %s",
		time.Now().Format(time.RFC3339),
		keyword,
		r.RemoteAddr,
	)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	safeKeyword := html.EscapeString(keyword)

	// Construct the HTML response
	// Requirement: Display the user's search keyword in the page title area
	// Format: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, safeKeyword)

	// Write the response
	if _, err := w.Write([]byte(htmlContent)); err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	log.Println("Starting server on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

