	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search request
	logSearchAnalytics(keyword, r)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: %s</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for: %s</p>
</body>
</html>`, escapedKeyword, escapedKeyword, escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

// logSearchAnalytics logs search analytics data
func logSearchAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().Format(time.RFC3339)
	ip := r.RemoteAddr
	userAgent := r.UserAgent()

	log.Printf("[Analytics] Search - Time: %s, IP: %s, Keyword: %s, User-Agent: %s",
		timestamp, ip, keyword, userAgent)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	fmt.Println("Server starting on :8080...")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

