package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request with analytics support.
// It expects a 'keyword' query parameter in the URL.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Extract keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Record search event
	// In a production environment, this would send data to an analytics backend
	logAnalyticsEvent(keyword)

	// Escape the keyword to prevent Cross-Site Scripting (XSS)
	safeKeyword := html.EscapeString(keyword)

	// Render the HTML response
	// Displays the user's search keyword in the page title area
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, safeKeyword)

	fmt.Fprint(w, htmlContent)
}

// logAnalyticsEvent simulates sending analytics data.
// It logs the search event with a timestamp to standard output.
func logAnalyticsEvent(keyword string) {
	timestamp := time.Now().Format(time.RFC3339)
	log.Printf("[Analytics] Event: Search | Timestamp: %s | Keyword: %s", timestamp, keyword)
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Starting server on %s", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

