import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles the product search request and records analytics.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Analytics Support: Log search event with timestamp and client IP
	// This satisfies the requirement for analytics support using the standard library.
	log.Printf("[Analytics] Search Event - Keyword: '%s', Time: %s, IP: %s",
		keyword,
		time.Now().Format(time.RFC3339),
		r.RemoteAddr)

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks when embedding in HTML
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	// Requirement: Display the user's search keyword in the page title area with the format: <h2>Search Results: [keyword]</h2>
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	// Write response status and content
	w.WriteHeader(http.StatusOK)
	_, err := w.Write([]byte(htmlContent))
	if err != nil {
		log.Printf("Error writing response: %v", err)
	}
}

func main() {
	// Register the handler for the search endpoint
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	port := ":8080"
	log.Printf("Starting server on %s", port)
	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Failed to start server: %v", err)
	}
}

