package main

import (
	"fmt"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search event
	logSearchAnalytics(keyword, r)

	// Build HTML response
	html := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, keyword)

	w.WriteHeader(http.StatusOK)
	w.Write([]byte(html))
}

// logSearchAnalytics logs search analytics data
func logSearchAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().Format(time.RFC3339)
	userAgent := r.UserAgent()
	ip := r.RemoteAddr

	// In production, this would send to analytics service
	// For now, we log it to stdout
	fmt.Printf("[%s] Search: keyword=%s, ip=%s, userAgent=%s\n",
		timestamp, keyword, ip, userAgent)
}

func main() {
	http.HandleFunc("/search", HandleProductSearch)

	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

