package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get the keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Analytics: Log the search request
	logAnalytics(keyword, r)

	// Escape the keyword for HTML safety
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: %s</title>
</head>
<body>
    <h2>Search Results: %s</h2>
    <p>Showing results for your search query.</p>
</body>
</html>`, escapedKeyword, escapedKeyword)

	// Write the response
	fmt.Fprint(w, htmlContent)
}

// logAnalytics logs search analytics data
func logAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().Format(time.RFC3339)
	ip := r.RemoteAddr
	userAgent := r.UserAgent()

	log.Printf("[Analytics] Search: keyword=%s, ip=%s, time=%s, userAgent=%s",
		keyword, ip, timestamp, userAgent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	port := ":8080"
	log.Printf("Starting server on %s", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatalf("Server failed to start: %v", err)
	}
}

