package main

import (
	"fmt"
	"html"
	"log"
	"net/http"
	"time"
)

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Get keyword from query parameter
	keyword := r.URL.Query().Get("keyword")

	// Analytics: Log search request
	logAnalytics(keyword, r)

	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Escape the keyword to prevent XSS attacks
	escapedKeyword := html.EscapeString(keyword)

	// Generate HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Search Results</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	// Write response
	fmt.Fprint(w, htmlContent)
}

// logAnalytics logs search analytics data for tracking purposes
func logAnalytics(keyword string, r *http.Request) {
	timestamp := time.Now().Format(time.RFC3339)
	ip := r.RemoteAddr
	userAgent := r.UserAgent()
	method := r.Method
	path := r.URL.Path

	log.Printf("[Analytics] Search: keyword=%s, method=%s, path=%s, ip=%s, time=%s, userAgent=%s",
		keyword, method, path, ip, timestamp, userAgent)
}

func main() {
	// Register the search handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

