func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Get keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Escape the keyword for HTML safety to prevent XSS
	escapedKeyword := html.EscapeString(keyword)

	// Build HTML response
	htmlContent := fmt.Sprintf(`<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Product Search</title>
</head>
<body>
    <h2>Search Results: %s</h2>
</body>
</html>`, escapedKeyword)

	// Write response
	fmt.Fprint(w, htmlContent)
}

func main() {
	// Register the handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start the server
	fmt.Println("Server starting on :8080")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		fmt.Printf("Server error: %v\n", err)
	}
}

